def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        if usage_ratio > 1.5:
            priorities[i] = 1000 * usage_ratio + 100
        elif 1 < usage_ratio <= 1.5:
            priorities[i] = 500 * usage_ratio + 50
        elif usage_ratio == 1:
            priorities[i] = 20
        else:
            gap = 1 - usage_ratio
            if gap <= 0.05:
                priorities[i] = -np.log(gap + 1e-12) * 10
            elif gap <= 0.2:
                priorities[i] = -np.log(gap + 1e-12) * 3
            else:
                priorities[i] = -np.log(gap + 1e-12)
        if capacity < 0.01:
            priorities[i] += 100
        elif capacity < 0.1:
            priorities[i] += 70
        elif capacity < 0.5:
            priorities[i] += 20
        for multiplier in [0.1, 0.5, 1.0]:
            threshold = multiplier * capacity
            if item > threshold:
                priorities[i] += 5 * (multiplier * 10)
        if priorities[i] > 2000:
            priorities[i] *= 0.9
        elif priorities[i] < 1:
            priorities[i] += 1
    if np.any(bins == 0):
        priorities[bins == 0] = np.inf
    return priorities
